// <auto-generated />
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useApiService } from './useApiService';
import { ApiError } from '../errors/ApiError';
import type { Pet, Pets } from '../models';

const petsKeys = {
  all: ['pets'] as const,
  list: (query?: { limit?: number }) => [...petsKeys.all, 'list', query] as const,
  showPetById: (petId: string) => [...petsKeys.all, 'showPetById', petId] as const,
};

export { petsKeys };

export function useListPets(query?: { limit?: number }) {
  const api = useApiService();
  return useQuery({
    queryKey: petsKeys.list(query),
    queryFn: async () => {
      const result = await api.pets.listPets(query);
      if (result.status === 'ok' || result.status === 'created') {
        return result.data;
      }
      throw new ApiError(
        result.response.status,
        result.response.statusText,
        'error' in result ? result.error.message : 'Request failed',
        result.response,
      );
    },
  });
}

export function useCreatePets() {
  const api = useApiService();
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async () => {
      const result = await api.pets.createPets();
      if (result.status === 'noContent' || result.status === 'ok') {
        return;
      }
      throw new ApiError(
        result.response.status,
        result.response.statusText,
        'error' in result ? result.error.message : 'Request failed',
        result.response,
      );
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: petsKeys.all });
    },
  });
}

export function useShowPetById(petId: string) {
  const api = useApiService();
  return useQuery({
    queryKey: petsKeys.showPetById(petId),
    queryFn: async () => {
      const result = await api.pets.showPetById(petId);
      if (result.status === 'ok' || result.status === 'created') {
        return result.data;
      }
      throw new ApiError(
        result.response.status,
        result.response.statusText,
        'error' in result ? result.error.message : 'Request failed',
        result.response,
      );
    },
    enabled: !!petId,
  });
}